#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    FILE *ulaz;
    double cijena;
    int brojPrimjeraka;
    char naziv[100];
    double ukupnaVrijednost = 0;

    ulaz = fopen("knjige.txt", "r");
    if (ulaz == NULL) {
        printf("Otvaranje datoteke knjige.txt nije uspjelo!\n");
        return 1;
    }

    while (fscanf(ulaz, "%lf,%d,", &cijena, &brojPrimjeraka) == 2) {
        /* učitavanje ostatka reda u string */
        if (fgets(naziv, sizeof(naziv), ulaz) != NULL) {
            /* uklanjanje \n sa kraja stringa ako postoji */
            naziv[strcspn(naziv, "\n")] = '\0';
            ukupnaVrijednost += cijena * brojPrimjeraka;
        }
    }

    printf("Ukupna vrijednost knjiga: %.2f\n", ukupnaVrijednost);

    fclose(ulaz);
    return 0;
}
